def solve(arg1: dict) -> str:
    challenge_id = arg1.get('challenge_id')
    response = arg1.get('response')

    if challenge_id is None:
        return 'Error: Challenge not found'
    if response is None:
        return 'Error: No response selected'

    if response == 'Yes':
        return 'Approval submitted successfully'
    elif response == 'No':
        return 'Rejection submitted successfully'

    return 'Error: Response dropdown not selectable'
